遍历字符串，用五个计数变量分别统计 C/B/R/G/M 的出现次数。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    string s; cin >> s;
    int c=0, b=0, r=0, g=0, m=0;
    for (char ch : s) {
        if (ch=='C') c++;
        else if (ch=='B') b++;
        else if (ch=='R') r++;
        else if (ch=='G') g++;
        else m++;
    }
    cout << c << ' ' << b << ' ' << r << ' ' << g << ' ' << m << endl;
    return 0;
}
```

双重循环枚举所有两件物品的组合（i<j），计算总价和总价值，取不超过预算的最大值。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, m, a[1005], b[1005];
    cin >> n >> m;
    for (int i=0; i<n; i++) cin >> a[i];
    for (int i=0; i<n; i++) cin >> b[i];
    int ans = 0;
    for (int i=0; i<n; i++) {
        for (int j=i+1; j<n; j++) {
            if (a[i]+a[j] <= m) {
                ans = max(ans, b[i]+b[j]);
            }
        }
    }
    cout << ans << endl;
    return 0;
}
```

数组下标从0开始，枚举左上角(i,j)，i从0到n-2，j从0到m-2，计算四个数之和取最大值。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, m, a[105][105];
    cin >> n >> m;
    for (int i=0; i<n; i++)
        for (int j=0; j<m; j++)
            cin >> a[i][j];
    int ans = 0;
    for (int i=0; i<n-1; i++) {
        for (int j=0; j<m-1; j++) {
            int sum = a[i][j] + a[i][j+1] + a[i+1][j] + a[i+1][j+1];
            ans = max(ans, sum);
        }
    }
    cout << ans << endl;
    return 0;
}
```

定义结构体，自定义比较函数，sort排序后输出id。

```cpp
#include <bits/stdc++.h>
using namespace std;
struct Stall {
    int id, t, p, score;
} a[1005];
bool cmp(Stall x, Stall y) {
    if (x.score != y.score) return x.score > y.score;
    if (x.t != y.t) return x.t > y.t;
    return x.id < y.id;
}
int main() {
    int n; cin >> n;
    for (int i=0; i<n; i++) {
        cin >> a[i].id >> a[i].t >> a[i].p;
        a[i].score = int(0.6 * a[i].t + 0.4 * a[i].p + 0.5);
    }
    sort(a, a+n, cmp);
    for (int i=0; i<n; i++) cout << a[i].id << endl;
    return 0;
}
```
